CREATE VIEW `dwd_read_user_balance_op_log_view` (`product_id` COMMENT "产品id", `id` COMMENT "主键ID", `user_id` COMMENT "用户id", `mt` COMMENT "Mt", `corever` COMMENT "Core包体", `device_id` COMMENT "设备", `coins` COMMENT "阅币数量", `award_coins` COMMENT "赠送币数量", `gifts` COMMENT "礼券数量", `op_type` COMMENT "操作类型 1:冻结 2:解冻", `create_time` COMMENT "创建时间", `app_id` COMMENT "应用id", `sr_createtime` COMMENT "starrocks数据注入时间", `sr_updatetime` COMMENT "starrocks数据更新时间")
